INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9df1be9c-5479-443b-8c1f-63cf1fc2456e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Cache-Aside — Cut DB Load with GET/SETEX$escape$,
  $escape$Every hot query hitting PostgreSQL directly is wasted work. Redis fixes this with the cache-aside pattern: your app checks Redis first, falls back to the DB on a miss, then writes the result back to Redis with a TTL. The key insight is that Redis never pulls data automatically — your code owns the read-through and write logic, which gives you precise control over what gets cached and for how long.

Use `GET` to check the cache. On a miss, query the DB, then call `SETEX key ttl value` to store it — atomically setting both value and expiry in one command. This prevents stale entries from living forever and avoids the thundering herd: if your TTL is short, expiries are staggered naturally across instances.

For user profile lookups (read-heavy, rarely mutated), a 60-second TTL with `SETEX user:1234 60 '{...}'` can eliminate 90%+ of DB reads. On writes, call `DEL user:1234` immediately — don't update the cache, invalidate it. This avoids stale reads without complex cache-update logic.$escape$,
  $escape$import redis from 'ioredis';

const client = new redis();

async function getUserProfile(userId: string): Promise<User> {
  const cacheKey = `user:${userId}`;

  const cached = await client.get(cacheKey);
  if (cached) return JSON.parse(cached);

  const user = await db.query('SELECT * FROM users WHERE id = $1', [userId]);

  await client.setex(cacheKey, 60, JSON.stringify(user));
  return user;
}

async function updateUserProfile(userId: string, data: Partial<User>) {
  await db.query('UPDATE users SET ... WHERE id = $1', [userId]);
  await client.del(`user:${userId}`);
}$escape$,
  $escape$typescript$escape$,
