INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bc1c8300-7e65-4d4c-8310-3ccd38e2f073',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis as a Queue — Decoupling Services with LPUSH/BRPOP$escape$,
  $escape$When your API endpoint triggers a slow operation — sending email, resizing images, hitting a third-party API — executing it inline blocks the response and couples your services tightly. Redis lists solve this cleanly. The producer calls `LPUSH jobs:email '{...}'` and returns immediately. The consumer runs in a separate process, blocking on `BRPOP jobs:email 0` — the `0` timeout means it waits indefinitely, consuming zero CPU until a job arrives. This is load leveling: a traffic spike pushes 10,000 items onto the list while your consumer drains at its own pace, preventing cascading failures. For priority queues, use multiple lists with `BRPOP jobs:critical jobs:normal 0` — Redis pops from the first non-empty list, giving `critical` natural priority. Need visibility? `LLEN jobs:email` gives queue depth instantly. For at-least-once delivery, use `RPOPLPUSH jobs:email jobs:email:processing` to atomically move the job to a processing list before working it, then `LREM jobs:email:processing 1 '{...}'` on success — surviving crashes without lost jobs.$escape$,
  $escape$import redis

r = redis.Redis(host='localhost', port=6379, decode_responses=True)

# Producer: fire-and-forget
def enqueue_email(payload: dict):
    r.lpush('jobs:email', json.dumps(payload))

# Consumer: blocking pop with safe processing list
def consume():
    while True:
        raw = r.brpoplpush('jobs:email', 'jobs:email:processing', timeout=0)
        try:
            job = json.loads(raw)
            send_email(job)
            r.lrem('jobs:email:processing', 1, raw)
        except Exception:
            r.lrem('jobs:email:processing', 1, raw)
            r.lpush('jobs:email:dead', raw)$escape$,
