INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5f4a7133-1ffd-45b2-acbb-6c822ef4780f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Dead Letter Queues — Poison Message Handling with LMOVE and Backoff$escape$,
  $escape$Redis has no native DLQ, but you can build one with LMOVE and sorted sets. The pattern: workers LMOVE jobs from a pending list to a processing list atomically. On failure, increment a retry counter in a hash and re-queue with exponential backoff using ZADD on a delay queue — scored by Unix timestamp for when the job should next run. A separate scheduler process calls ZRANGEBYSCORE delay_queue 0 <now> periodically and LMOVE ready jobs back to pending.

Once retries exceed a threshold (e.g., 3), LMOVE the message to a dead:queue list instead of re-scheduling. This isolates poison messages without blocking healthy consumers. Store failure context alongside the job in a hash keyed by job ID so you can inspect and replay from the DLQ manually via LMOVE dead:queue pending RIGHT LEFT.

Use MULTI/EXEC to keep counter increments and re-queues atomic. Avoid RPOPLPUSH — it's deprecated; LMOVE with LEFT/RIGHT direction args is the modern equivalent since Redis 6.2.$escape$,
  $escape$-- Lua script: attempt job, retry with backoff, or DLQ
local job_id = ARGV[1]
local max_retries = tonumber(ARGV[2])
local now = tonumber(ARGV[3])

local retries = tonumber(redis.call('HINCRBY', 'job:meta:' .. job_id, 'retries', 1))

if retries >= max_retries then
  redis.call('LMOVE', 'queue:processing', 'queue:dead', 'LEFT', 'RIGHT')
  return 'dlq'
end

local backoff = math.pow(2, retries) * 1000  -- ms
local run_at = now + backoff
redis.call('LMOVE', 'queue:processing', 'queue:temp', 'LEFT', 'RIGHT')
redis.call('ZADD', 'queue:delay', run_at, job_id)
return 'retrying'$escape$,
  $escape$lua$escape$,
