INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd5bfdd9-d20f-43da-8a70-f6103a12d6fd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis as a Queue — Lists vs Pub/Sub vs Streams$escape$,
  $escape$Redis offers three distinct primitives for message passing, each with sharp trade-offs. LPUSH/BRPOP on a List is the simplest queue: consumers block-wait with BRPOP, messages are consumed exactly once, but if no consumer is alive, messages sit in the list until one reconnects. There's no fan-out — one message, one consumer. PUBLISH/SUBSCRIBE inverts this: fan-out is native, but messages are fire-and-forget. If a subscriber is offline when PUBLISH fires, the message is lost — no buffering, no persistence. Redis Streams (XADD/XREADGROUP) are the production-grade choice. Each message gets a unique auto-generated ID (e.g. 1712345678901-0), consumer groups track per-consumer ACK state via XACK, and unacknowledged messages surface in the PEL (Pending Entries List) via XPENDING. With AOF persistence and MAXLEN trimming, Streams behave like a durable, replayable log. For job queues, prefer Streams. For ephemeral notifications, use Pub/Sub. Lists work for simple FIFO with a single consumer pool.$escape$,
  $escape$# Producer
XADD jobs * type resize url https://img.example.com/photo.jpg

# Create consumer group (read from beginning)
XGROUP CREATE jobs workers $ MKSTREAM

# Consumer reads 1 pending message
XREADGROUP GROUP workers consumer-1 COUNT 1 BLOCK 5000 STREAMS jobs >

# Acknowledge after processing
XACK jobs workers 1712345678901-0

# Inspect unacknowledged (stuck) messages
XPENDING jobs workers - + 10$escape$,
  $escape$bash$escape$,
