INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7df96f58-b9cc-401a-acc9-41fd1c4fa1b8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis as Cache — TTL, Eviction Policies, and the Three Write Strategies$escape$,
  $escape$Redis gives you precise control over cache lifetime and memory pressure. Set TTL at write time with `SET key value EX 300` or update it later with `EXPIRE key 300`. Use `EXPIREAT` for absolute Unix timestamps when coordinating across services.

When memory hits `maxmemory`, Redis evicts based on your configured policy. `allkeys-lru` is the go-to for general caches — it evicts the least-recently-used key across all keyspace. Use `volatile-lru` if only TTL-bearing keys should be eligible. `allkeys-lfu` (Least Frequently Used, available since 4.0) beats LRU for hot-key-heavy workloads. Never run Redis as a cache without setting `maxmemory` and a policy — unbounded growth will OOM your instance.

For write strategy: **cache-aside** (lazy loading) reads miss to DB then populates Redis — your app owns the logic, stale data is possible. **Write-through** writes to Redis and DB synchronously on every mutation — consistent but adds write latency. **Write-behind** (write-back) buffers writes in Redis and flushes async — highest throughput, but you risk data loss on crash. Redis Streams or a Lua script can implement write-behind durably.$escape$,
  $escape$import redis

r = redis.Redis(host='localhost', port=6379, decode_responses=True)

# Cache-aside: read-through on miss
def get_user(user_id: str) -> dict:
    key = f"user:{user_id}"
    cached = r.get(key)
    if cached:
        return json.loads(cached)
    user = db.fetch_user(user_id)          # miss → hit DB
    r.set(key, json.dumps(user), ex=300)   # populate with 5-min TTL
    return user

# Eviction policy (set in redis.conf or at runtime)
# CONFIG SET maxmemory 256mb
# CONFIG SET maxmemory-policy allkeys-lru$escape$,
  $escape$python$escape$,
