INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0dda8195-c74a-44c4-92a8-f9f1ef7e1832',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Streams — Exchanges, Routing Keys, and Acknowledgements Without RabbitMQ$escape$,
  $escape$Redis Streams give you RabbitMQ-style message queuing natively. Instead of exchanges and bindings, you route by stream key — `XADD orders:created * event order_placed id 123` writes to the `orders:created` stream (your exchange + routing key collapsed into one). Consumer groups (`XGROUP CREATE`) act as competing-consumer queues: each group receives every message, but within a group only one consumer processes it.

Prefetch count maps directly to the `COUNT` argument in `XREADGROUP`. Passing `COUNT 10` fetches at most 10 unacknowledged messages per call — same backpressure semantics as RabbitMQ's `basic.qos`. The `>` cursor means "only new, undelivered messages"; passing a specific ID re-reads entries already in the Pending Entry List (PEL).

Acknowledgement is explicit: `XACK orders:created workers <msg-id>` removes the entry from the PEL. Unacked messages linger there and can be stolen by another consumer via `XCLAIM` after an idle timeout — your dead-letter/requeue path. Redis has no native nack; on failure, manually `XADD` to a dead-letter stream before `XACK`ing the original.$escape$,
  $escape$import redis

r = redis.Redis(decode_responses=True)

# Publisher: stream key acts as exchange + routing key
r.xadd("orders:created", {"event": "order_placed", "id": "123"})

# One-time consumer group setup
r.xgroup_create("orders:created", "workers", id="0", mkstream=True)

# Fetch up to 10 msgs (COUNT = prefetch limit)
messages = r.xreadgroup("workers", "consumer1", {"orders:created": ">"}, count=10, block=5000)

for _stream, entries in (messages or []):
    for msg_id, data in entries:
        try:
            process(data)
            r.xack("orders:created", "workers", msg_id)  # explicit ack
        except Exception:
            r.xadd("orders:dead", {**data, "failed_id": msg_id})  # manual DLQ
            r.xack("orders:created", "workers", msg_id)$escape$,
  $escape$python$escape$,
