INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4113b771-df05-4d27-b196-8d67bbeb2123',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Streams — Partitioning Strategy for Ordered Message Processing$escape$,
  $escape$Redis Streams guarantee per-stream ordering via auto-generated entry IDs (millsecond-sequence format: `1700000000000-0`). But a single stream becomes a bottleneck under high throughput — one consumer group serializes processing. The solution: partition by a stable key (user ID, tenant ID, order ID) using modulo hashing across N streams. `XADD orders:stream:{userId % 8} * payload data` ensures all events for a given entity land in the same stream, preserving causal order without cross-stream coordination. Consumers use `XREADGROUP GROUP workers consumer1 COUNT 10 STREAMS orders:stream:0 >` per partition. Increase N by doubling and remapping — existing streams drain naturally before new ones take over. Avoid partitioning by timestamp; clock skew destroys ordering guarantees. Use `XPENDING` to detect stalled messages per partition and `XCLAIM` to reassign them after a visibility timeout. The entry ID's monotonic sequence component handles sub-millisecond bursts on the same stream without collision, so you never need application-level sequence numbers.$escape$,
  $escape$# Partition writes by entity key
PARTITIONS = 8

def publish_event(redis_client, user_id: int, payload: dict):
    stream_key = f"orders:stream:{user_id % PARTITIONS}"
    redis_client.xadd(stream_key, payload)

# Consumer reads from a specific partition
def consume_partition(redis_client, partition: int, group: str, consumer: str):
    stream_key = f"orders:stream:{partition}"
    messages = redis_client.xreadgroup(
        groupname=group,
        consumername=consumer,
        streams={stream_key: ">"},
        count=10,
        block=2000
    )
    return messages$escape$,
  $escape$python$escape$,
