INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fff241a6-a131-42ca-8b9a-d30d765c2403',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Streams Developer's Intro to NATS JetStream — Subjects, Durables, and At-Least-Once$escape$,
  $escape$If you rely on Redis Streams (XADD/XREAD/XACK) for durable messaging, NATS JetStream maps cleanly to those semantics — but with subject-based routing instead of per-key streams.

In Redis, a consumer group reads from a named stream key and calls XACK to confirm delivery. JetStream works the same way: create a Stream bound to one or more subjects (e.g., orders.>), attach a durable Consumer, and messages stay in the pending-entry list until your handler calls msg.Ack() — identical intent to Redis's PEL.

Where Redis requires separate stream keys or Lua fan-out for routing, NATS subjects use wildcards natively: orders.* matches one token, orders.> matches all descendants. One JetStream Stream can capture orders.created, orders.shipped, and orders.cancelled with no extra keys.

JetStream retention policies also map to familiar Redis patterns: work-queue retention deletes a message after the first ack (single-consumer XDEL-after-XACK), while interest-based retention waits until every bound consumer acks (multi-consumer fan-out). For Redis developers hitting keyspace routing limits, JetStream's durable consumers and hierarchical subjects cover the gap without touching your Redis cluster.$escape$,
  $escape$import nats
import asyncio

async def main():
    nc = await nats.connect("nats://localhost:4222")
    js = nc.jetstream()

    # Equivalent to: XADD orders * event placed
    await js.add_stream(name="orders", subjects=["orders.>"])
    await js.publish("orders.created", b'{"id": 42}')

    # Equivalent to: XREADGROUP + XACK
    sub = await js.subscribe("orders.>", durable="order-processor")
    msg = await sub.next_msg(timeout=2.0)
    print(msg.data)          # b'{"id": 42}'
    await msg.ack()          # Clears PEL entry — like XACK mystream grp <id>

asyncio.run(main())$escape$,
  $escape$python$escape$,
