INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dd12ef0e-bebc-405a-b688-e81fc60ebd3e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Queue Monitoring — Depth Alerts, Consumer Lag, and Dead Letter Queues$escape$,
  $escape$Redis streams (`XLEN`, `XPENDING`) and list-based queues (`LLEN`) expose the metrics you need for production alerting. For list queues, `LLEN myqueue` gives depth instantly — alert when it exceeds your SLA threshold. For Redis Streams, `XPENDING mystream mygroup - + 10` reveals unacknowledged messages per consumer group; consumer lag is `last_delivered_id` vs the stream's last entry ID, computable via `XINFO GROUPS mystream`. Dead letter queues (DLQs) are convention-based in Redis: after N failed `XACK` attempts, move the message to a `mystream:dlq` stream using `XADD`. Monitor DLQ depth with `XLEN mystream:dlq` and alert on any non-zero value. For Prometheus scraping, `redis_exporter` exposes `redis_stream_length`, `redis_stream_groups_pending`, and `redis_connected_clients`. Pair with Grafana alerts: fire if `xpending > 500` for 5 minutes or `dlq_length > 0`. Polling via `XINFO STREAM` in a sidecar loop works for lightweight setups without a full exporter.$escape$,
  $escape$import redis

r = redis.Redis(host='localhost', port=6379, decode_responses=True)

STREAM = 'jobs'
GROUP = 'workers'
DLQ = 'jobs:dlq'
DEPTH_THRESHOLD = 500

# Queue depth
depth = r.xlen(STREAM)
if depth > DEPTH_THRESHOLD:
    print(f'ALERT: queue depth {depth} exceeds threshold')

# Consumer lag per group
groups = r.xinfo_groups(STREAM)
for g in groups:
    lag = g['lag']  # Redis 7.0+
    pending = g['pending']
    print(f"{g['name']}: lag={lag}, pending={pending}")

# DLQ alert
dlq_len = r.xlen(DLQ)
if dlq_len > 0:
    print(f'ALERT: {dlq_len} messages in DLQ — manual intervention required')$escape$,
  $escape$python$escape$,
