INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2014a3d5-a341-48f4-968d-85a6a7740478',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Security — TLS, ACLs, and Network Isolation Done Right$escape$,
  $escape$Running Redis without authentication is a P0 incident waiting to happen. Start with ACL users: replace the legacy `requirepass` with fine-grained ACL rules so each service gets only the commands it needs. A background worker that only enqueues jobs should have `+LPUSH +RPUSH ~queue:*` and nothing else — no `FLUSHDB`, no `CONFIG`, no `KEYS`.

For transport, enable TLS by setting `tls-port 6380`, pointing `tls-cert-file`, `tls-key-file`, and `tls-ca-cert-file` in `redis.conf`. Clients must present a cert (`tls-auth-clients yes`) — mutual TLS prevents rogue clients from connecting even inside a VPC.

Network isolation is your last line of defense: bind Redis to a private IP only (`bind 10.0.0.5 127.0.0.1`), never `0.0.0.0`. Use a security group or `iptables` to whitelist only app-tier IPs on port 6379/6380. Enable `protected-mode yes` so Redis refuses connections on non-loopback interfaces without a password. Combine ACLs + mTLS + network allowlists — each layer stops a different attack vector.$escape$,
  $escape$# redis.conf — production hardening
bind 10.0.0.5 127.0.0.1
protected-mode yes

tls-port 6380
port 0  # disable plaintext
tls-cert-file /etc/redis/tls/redis.crt
tls-key-file  /etc/redis/tls/redis.key
tls-ca-cert-file /etc/redis/tls/ca.crt
tls-auth-clients yes

# ACL: worker can only push to queue:* keys
ACL SETUSER worker on >s3cr3t ~queue:* +LPUSH +RPUSH +LLEN -@all
ACL SETUSER readonly on >r0pwd ~* +GET +MGET +HGET -@all
ACL SETUSER default off  # disable anonymous access$escape$,
  $escape$bash$escape$,
