INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f42b1703-cf2f-48c3-ba84-36c2cf8efe7c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis Streams — Testing Consumers in Isolation with fakeredis$escape$,
  $escape$Testing a Redis Streams consumer end-to-end requires a live broker, but unit-testing the processing logic doesn't. The pattern: inject the Redis connection, swap it for `fakeredis.FakeRedis()` in tests, then seed messages directly with `XADD` before invoking your consumer loop.

`fakeredis` fully implements `XADD`, `XREADGROUP`, `XACK`, and `XPENDING`, so consumer group mechanics — including the pending-entries list (PEL) — behave identically to a real Redis instance. This means you can assert not just that your handler ran, but that `XACK` was called and the PEL is empty afterward.

For failure paths, seed a message, make your handler throw, then call `XPENDING` to verify the message stays in the PEL and gets re-delivered on the next `XREADGROUP` poll. This catches the silent bug where a bad handler accidentally acks before processing finishes.

Avoid mocking at the `IDatabase` or `redis.client` level — you'll spend more effort maintaining the mock than the test is worth. `fakeredis` gives you a real state machine without a Docker dependency.$escape$,
  $escape$import fakeredis
import pytest

@pytest.fixture
def redis_client():
    return fakeredis.FakeRedis(decode_responses=True)

def consume_once(r, stream, group, consumer):
    msgs = r.xreadgroup(group, consumer, {stream: ">"}, count=1, block=0)
    for _, entries in msgs:
        for msg_id, data in entries:
            process(data)          # your handler
            r.xack(stream, group, msg_id)

def test_ack_clears_pel(redis_client):
    r = redis_client
    r.xgroup_create("jobs", "workers", id="$", mkstream=True)
    r.xadd("jobs", {"task": "embed"})
    consume_once(r, "jobs", "workers", "c1")
    assert r.xpending("jobs", "workers")["pending"] == 0$escape$,
  $escape$python$escape$,
